Rules.InvariantScript:
Refresh('Job Addresses');

With(
   {
      _Low: 
      Sort(
         'Job Addresses',
         ID
      ),
      _High: 
      Sort(
         'Job Addresses',
         ID,
         SortOrder.Descending
      )
   },
   ClearCollect(
      colJobAddresses,
      _Low,
      Filter(
         _High,
         !(ID in _Low.ID)
      )
   )
);

With(
    {
        customer: LookUp(colCustomers, ID = ThisItem.Customer.Id)
    },
    If(
        !IsBlank(customer.Mobile),
        customer.Mobile,
        customer.Landline
    )
)

With(
    {
        customer: LookUp(colCustomers, ID = ThisItem.Customer.Id)
    },
    If(
        !IsBlank(customer.Email),
        customer.Email,
        customer.'2nd Email'
    )
)

Patch(
    'Job Addresses',
    LookUp('Job Addresses', ID = ThisItem.ID),
    {'Install Name': textInstallName_1.Value}
);
Patch(
    colJobAddresses,
    LookUp(colJobAddresses, ID = ThisItem.ID),
    {'Install Name': textInstallName_1.Value}
);

Patch(
    'Job Addresses',
    LookUp('Job Addresses', ID = ThisItem.ID),
    {'Install Phone': textInstallPhone_1.Value}
);
Patch(
    colJobAddresses,
    LookUp(colJobAddresses, ID = ThisItem.ID),
    {'Install Phone': textInstallPhone_1.Value}
);

Patch(
    'Job Addresses',
    LookUp('Job Addresses', ID = ThisItem.ID),
    {Status: Table(comboboxStatus_1.Selected)}
);
Patch(
    colJobAddresses,
    LookUp(colJobAddresses, ID = ThisItem.ID),
    {Status: Table(comboboxStatus_1.Selected)}
);

Patch(
    'Job Addresses',
    LookUp('Job Addresses', ID = ThisItem.ID),
    {Priority: comboboxPriority_1.Selected}
);
Patch(
    colJobAddresses,
    LookUp(colJobAddresses, ID = ThisItem.ID),
    {Priority: comboboxPriority_1.Selected}
);

If(buttonAppointmentId_1.Text = "+",
    Navigate(
        AppointmentScreen, 
        ScreenTransition.Fade,
        {recordForAppointmentScreenAddressId: ThisItem.ID,
        recordForAppointmentScreenCustomerId: ThisItem.Customer.Id,
        recordForAppointmentScreenAppointmentId: Blank()}
    ),
    Navigate(
        AppointmentScreen, 
        ScreenTransition.Fade,
        {recordForAppointmentScreenAddressId: Blank(),
        recordForAppointmentScreenCustomerId: Blank(),
        recordForAppointmentScreenAppointmentId: Int(buttonAppointmentId_1.Text)}
    )
)

Patch(
    'Job Addresses',
    LookUp('Job Addresses', ID = ThisItem.ID),
    {'Scheduling Notes': textSchedulingNotes_1.Value}
);
Patch(
    colJobAddresses,
    LookUp(colJobAddresses, ID = ThisItem.ID),
    {'Scheduling Notes': textSchedulingNotes_1.Value}
);
